INSERT INTO "BrandStory" ("id", "sectionKey", "heading", "subheading", "body", "imageUrl", "imageAlt", "videoUrl", "ctaText", "ctaUrl", "isActive", "sortOrder", "updatedAt") VALUES ('bs-craft', 'craft', '1 Gram Gold — Crafted to Last a Lifetime', 'Our Artisan Promise', 'Every piece at Avighna Collections is crafted using premium copper-brass alloy cores electroformed with high-purity gold coating. The result is jewellery that looks, feels, and shines like solid gold — at a fraction of the cost. We partner with master artisans who have practised their craft for generations.', 'https://images.unsplash.com/photo-1602751584552-8ba73aad10e1?w=800&q=80', NULL, NULL, 'Learn Our Process', '/about', TRUE, 1, '2026-07-08T11:51:25.668Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "sectionKey" = EXCLUDED."sectionKey", "heading" = EXCLUDED."heading", "subheading" = EXCLUDED."subheading", "body" = EXCLUDED."body", "imageUrl" = EXCLUDED."imageUrl", "imageAlt" = EXCLUDED."imageAlt", "videoUrl" = EXCLUDED."videoUrl", "ctaText" = EXCLUDED."ctaText", "ctaUrl" = EXCLUDED."ctaUrl", "isActive" = EXCLUDED."isActive", "sortOrder" = EXCLUDED."sortOrder", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "BrandStory" ("id", "sectionKey", "heading", "subheading", "body", "imageUrl", "imageAlt", "videoUrl", "ctaText", "ctaUrl", "isActive", "sortOrder", "updatedAt") VALUES ('bs-heritage', 'heritage', 'Rooted in Telugu Tradition', 'A Heritage of Beauty', 'Wanaparthy has always been a city of celebration. From Dasara festivals to grand weddings, jewellery is the centrepiece of every milestone moment. Avighna Collections honours this heritage by bringing the finest ornamental traditions — temple motifs, classical dance pieces, bridal adornments — under one roof.', 'https://images.unsplash.com/photo-1601628828688-632f38a5a7d0?w=800&q=80', NULL, NULL, 'Explore Our Story', '/about', TRUE, 2, '2026-07-08T11:51:25.676Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "sectionKey" = EXCLUDED."sectionKey", "heading" = EXCLUDED."heading", "subheading" = EXCLUDED."subheading", "body" = EXCLUDED."body", "imageUrl" = EXCLUDED."imageUrl", "imageAlt" = EXCLUDED."imageAlt", "videoUrl" = EXCLUDED."videoUrl", "ctaText" = EXCLUDED."ctaText", "ctaUrl" = EXCLUDED."ctaUrl", "isActive" = EXCLUDED."isActive", "sortOrder" = EXCLUDED."sortOrder", "updatedAt" = EXCLUDED."updatedAt";
