INSERT INTO "Testimonial" ("id", "name", "role", "location", "content", "rating", "avatarUrl", "productId", "isActive", "isFeatured", "sortOrder", "createdAt", "updatedAt") VALUES ('test-2', 'Rekha Devi', 'Classical Dancer', 'Hyderabad', 'I ordered a complete Bharatanatyam jewellery set for my arangetram. The quality is excellent and the pieces are lightweight enough to wear through a full performance. Highly recommended!', 5, NULL, NULL, TRUE, TRUE, 2, '2026-07-07T04:57:48.261Z', '2026-07-08T11:51:25.714Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "name" = EXCLUDED."name", "role" = EXCLUDED."role", "location" = EXCLUDED."location", "content" = EXCLUDED."content", "rating" = EXCLUDED."rating", "avatarUrl" = EXCLUDED."avatarUrl", "productId" = EXCLUDED."productId", "isActive" = EXCLUDED."isActive", "isFeatured" = EXCLUDED."isFeatured", "sortOrder" = EXCLUDED."sortOrder", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "Testimonial" ("id", "name", "role", "location", "content", "rating", "avatarUrl", "productId", "isActive", "isFeatured", "sortOrder", "createdAt", "updatedAt") VALUES ('test-3', 'Suhasini Reddy', 'Festival Shopper', 'Mahabubnagar', 'Bought Dasara jewellery for the whole family from Avighna Collections. The variety is amazing and the prices are very fair. The bangles set I got is absolutely stunning.', 5, NULL, NULL, TRUE, TRUE, 3, '2026-07-07T04:57:48.262Z', '2026-07-08T11:51:25.718Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "name" = EXCLUDED."name", "role" = EXCLUDED."role", "location" = EXCLUDED."location", "content" = EXCLUDED."content", "rating" = EXCLUDED."rating", "avatarUrl" = EXCLUDED."avatarUrl", "productId" = EXCLUDED."productId", "isActive" = EXCLUDED."isActive", "isFeatured" = EXCLUDED."isFeatured", "sortOrder" = EXCLUDED."sortOrder", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "Testimonial" ("id", "name", "role", "location", "content", "rating", "avatarUrl", "productId", "isActive", "isFeatured", "sortOrder", "createdAt", "updatedAt") VALUES ('test-4', 'Anitha Kumari', 'Mother of Bride', 'Wanaparthy', 'Geetha Rani garu personally helped us choose every piece for my daughter''s wedding. Her knowledge and patience made the whole experience so special. We are loyal customers now.', 5, NULL, NULL, TRUE, FALSE, 4, '2026-07-07T04:57:48.264Z', '2026-07-08T11:51:25.721Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "name" = EXCLUDED."name", "role" = EXCLUDED."role", "location" = EXCLUDED."location", "content" = EXCLUDED."content", "rating" = EXCLUDED."rating", "avatarUrl" = EXCLUDED."avatarUrl", "productId" = EXCLUDED."productId", "isActive" = EXCLUDED."isActive", "isFeatured" = EXCLUDED."isFeatured", "sortOrder" = EXCLUDED."sortOrder", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-m1', 'What is 1 gram gold jewellery?', '1 gram gold jewellery uses a premium brass-copper alloy core that is electroformed with high-purity 22K or 18K gold coating. The result is jewellery that is visually and tactilely indistinguishable from solid gold at a much more accessible price point.', 'MATERIAL_COMPOSITION', 1, TRUE, '2026-07-07T04:57:48.265Z', '2026-07-08T11:51:25.726Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-m2', 'Is 1 gram gold jewellery safe for skin?', 'Yes. Our jewellery is nickel-free, lead-free, and hypoallergenic. The gold-plated surface ensures comfortable, irritation-free wear for all skin types including sensitive skin.', 'MATERIAL_COMPOSITION', 2, TRUE, '2026-07-07T04:57:48.271Z', '2026-07-08T11:51:25.733Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-m3', 'How long does the gold finish last?', 'With proper care, our gold finish lasts 2–5 years of regular wear. Keeping pieces away from water, perfumes, and chemicals significantly extends their life. We also offer re-polishing services at our store.', 'MATERIAL_COMPOSITION', 3, TRUE, '2026-07-07T04:57:48.272Z', '2026-07-08T11:51:25.736Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-c1', 'How should I care for my jewellery?', 'Store each piece separately in the velvet pouch or box provided. Avoid direct contact with water, perfumes, hairspray, and lotions. Wipe gently with a soft dry cloth after every use. Remove jewellery before bathing, swimming, or exercising.', 'CARE_GUARANTEE', 1, TRUE, '2026-07-07T04:57:48.274Z', '2026-07-08T11:51:25.739Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-c2', 'Can I clean my jewellery at home?', 'Yes. Use a soft, dry microfiber cloth to gently wipe the surface. For deeper cleaning, bring it to our store. Avoid ultrasonic cleaners, harsh chemicals, or abrasive cloths as they can damage the gold coating.', 'CARE_GUARANTEE', 2, TRUE, '2026-07-07T04:57:48.275Z', '2026-07-08T11:51:25.743Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-c3', 'Do you offer re-polishing or repair services?', 'Yes. Visit our Wanaparthy store for re-polishing, repair, and restoration services. We can restore most pieces to near-original condition. Contact us on 7013004127 before visiting.', 'CARE_GUARANTEE', 3, TRUE, '2026-07-07T04:57:48.276Z', '2026-07-08T11:51:25.746Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-o2', 'Can I place a custom or bulk order?', 'Absolutely. We welcome custom orders for weddings, festivals, and institutional buyers. WhatsApp us on 7013004127 with your requirements and we will provide a personalised quote within 24 hours.', 'ORDERS_RETURNS', 2, TRUE, '2026-07-07T04:57:48.281Z', '2026-07-08T11:51:25.760Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-b1', 'Do you provide bridal sets for the full wedding trousseau?', 'Yes. We specialise in complete bridal trousseau sets including necklaces, harams, earrings, bangles, maang tikka, nath, haar, vaddanam, and more. Visit our store for a private bridal consultation with H. Geetha Rani.', 'BRIDAL', 1, TRUE, '2026-07-07T04:57:48.282Z', '2026-07-08T11:51:25.763Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-b2', 'Can I book a bridal styling appointment?', 'Yes. Call or WhatsApp us on 7013004127 to book a private bridal session at our Wanaparthy boutique. We recommend booking at least 2–3 weeks before your wedding date.', 'BRIDAL', 2, TRUE, '2026-07-07T04:57:48.283Z', '2026-07-08T11:51:25.765Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-b3', 'Do you offer classical dance jewellery sets?', 'Yes. We stock complete Bharatanatyam, Kuchipudi, and other classical dance jewellery sets — lightweight, durable, and stage-ready. Ideal for arangetrams, competitions, and performances.', 'BRIDAL', 3, TRUE, '2026-07-07T04:57:48.284Z', '2026-07-08T11:51:25.768Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-s1', 'Do you deliver outside Wanaparthy?', 'Yes. We ship across India. Standard delivery takes 4–7 business days. Express delivery (1–2 days) is available for select PIN codes at an additional charge.', 'SHIPPING_SECURITY', 1, TRUE, '2026-07-07T04:57:48.277Z', '2026-07-08T11:51:25.749Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-s2', 'Is the packaging secure?', 'Every order is packed in our signature jewellery box with foam inserts and wrapped securely for transit. Fragile pieces are double-boxed. All shipments are insured and require signature-on-delivery.', 'SHIPPING_SECURITY', 2, TRUE, '2026-07-07T04:57:48.278Z', '2026-07-08T11:51:25.751Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-s3', 'How can I track my order?', 'Once shipped, you will receive a tracking link via SMS and WhatsApp. You can also WhatsApp us on 7013004127 for real-time updates on your order.', 'SHIPPING_SECURITY', 3, TRUE, '2026-07-07T04:57:48.279Z', '2026-07-08T11:51:25.753Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
INSERT INTO "FaqEntry" ("id", "question", "answer", "category", "sortOrder", "isActive", "createdAt", "updatedAt") VALUES ('faq-o1', 'Can I return or exchange a product?', 'We accept returns within 7 days for unused items in original packaging. Exchange is accepted within 15 days. Custom orders and bridal sets are non-returnable. Contact us on WhatsApp or email to initiate a return.', 'ORDERS_RETURNS', 1, TRUE, '2026-07-07T04:57:48.280Z', '2026-07-08T11:51:25.757Z') ON CONFLICT ("id") DO UPDATE SET "id" = EXCLUDED."id", "question" = EXCLUDED."question", "answer" = EXCLUDED."answer", "category" = EXCLUDED."category", "sortOrder" = EXCLUDED."sortOrder", "isActive" = EXCLUDED."isActive", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt";
